var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……노엘 라이트.","JPN":"……ノエル・ライト。","ENG":"...Noelle Wright.","TWN":"……洛艾兒·萊特。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이전에 봤을 때보다 몸놀림이 빠르고 가볍군요.","JPN":"以前会った時よりも身のこなしが軽く、素早くなりましたね。","ENG":"You seem more nimble than the last time I saw you.","TWN":"你看起來比上次見面時靈活多了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뿐만이 아니라, 다른 두 사람과도 호흡이 제법 나쁘지 않아요.","JPN":"それだけではない。他の二人ともかなり上手く息を合わせている。","ENG":"It's not just that, your chemistry with those two has gotten better.","TWN":"不僅如此，和其他兩個人的配合也相當不錯。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"틀림없이 건틀렛 리그라는 무대를 통해, 한 단계 더 성장한 거겠죠.","JPN":"ガントレットリーグという舞台を通して、一段と成長したのでしょう。","ENG":"I'm certain that through the Gauntlet league, you've reached new heights.","TWN":"毫無疑問，透過聖鎧聯賽這個舞台，你又成長了一步。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 이런 곳에서, 이런 식으로 마주치게 될 줄은 몰랐지만…….","JPN":"そう。こんな場所で、こんな風に再会するとは思いませんでしたが……","ENG":"Yes. I didn't expect to meet you like this here, but...","TWN":"是啊，沒想到會在這種地方，以這種方式遇見……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 상황을 지켜보도록 할까요?","JPN":"さて、では状況を見守るとしましょうか。","ENG":"Now, shall I observe what will happen next?","TWN":"那麼，我對接下來的劇情拭目以待……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"잠깐! 장난은 거기까지다!","JPN":"待った！　お遊びはここまでだ！","ENG":"Hold it right there! Playtime's over!","TWN":"想得美！遊戲結束了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……윽!","JPN":"……うっ！","ENG":"...Ngh!","TWN":"……唔！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 저자는……?","JPN":"ん？　あの者は……？","ENG":"Hmm? That's...?","TWN":"嗯？他是……？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"후우, 생포하는 데 고생 좀 했지. 늙다리 주제에 주먹은 더럽게 매워 가지곤.","JPN":"ふう、生け捕りするのにちょっと苦労したぜ。老いぼれのくせに拳がやたら強くてな。","ENG":"Phew. Took longer than expected to capture him alive. He's got one mean punch for an old man.","TWN":"呼，費了一番勁才活捉到他，這老傢伙拳頭很硬呢！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 아무튼 분위기 파악했으면 당장 수송기에서 떨어져.","JPN":"さあ、とにかく空気読んだなら、今すぐ輸送船から離れるんだ。","ENG":"Now, step away from the aircraft if you know what's good for you.","TWN":"總之，勸你們搞清楚狀況，趕快從運輸機上下來。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그렇지 않으면 이 노인네의……","JPN":"じゃないと、この老人の……","ENG":"Or else, this old man is gonna–","TWN":"否則這個老傢伙……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으악! 무, 무슨 짓거리야! 아프잖아!","JPN":"うわっ！　な、何しやがる！　痛いじゃねえか！","ENG":"Aaargh! W-what was that for?! That hurt!","TWN":"呃啊！你，你做什麼！很痛欸！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워. 얼굴도 모르는 할배 데려다 놓고 어딜 개수작이야.","JPN":"うるさい。顔も知らないジジイ連れてきて、ふざけんなよ。","ENG":"Shut up. We don't even know that geezer. What are you trying to pull?","TWN":"吵死了你！我又不認識那個阿公，你把他帶來要做什麼？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐? 이 노인네가 죽어도 상관없다는 거냐!?","JPN":"なにっ？　この老人が死んでもいいのか！？","ENG":"What? Then you're okay with me killing this old man?!","TWN":"什麼？我殺了他你也不在意嗎！？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"상관 있는 건 보험사겠지. 그 할배가 니들이랑 한통속인지 우리가 어떻게 알아?","JPN":"困るのは保険会社だろ？　そのジジイがあんたらとグルじゃないとどうしてわかる？","ENG":"The only ones not okay will be his insurance company. And who knows? Maybe he's on the same team as you.","TWN":"會在意的應該是保險公司吧？誰知道那個阿公是不是跟你們同一夥的？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐 저런 개망나니가 다 있어!?","JPN":"何だと、この不良娘が！？","ENG":"You can't be serious right now!","TWN":"你是哪來的小王八蛋！？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치, 접선인이라는 사람이 혹시 저 할아버지에요?","JPN":"コーチ、受渡人というのはもしかしてあのお爺さんですか？","ENG":"Coach, this contact you were talking about. Is that him?","TWN":"教練，接應的人就是那個阿公嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……아닌 것 같네만?","JPN":"……違うと思うが。","ENG":"...I don't think so.","TWN":"……感覺應該不是？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카. 모르는 사람이래요, 쏴요.","JPN":"ライカ、知らない人だって。撃って。","ENG":"Laika. Coach doesn't know him. Shoot him.","TWN":"萊卡，開槍，他是陌生人。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"아악! 내 눈!!","JPN":"ぐわっ！　俺の目！！","ENG":"Aaagh! My eye!!","TWN":"啊啊！我的眼睛！！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이런 빌어먹을! 그만 좀 쏴!","JPN":"ちくしょう！　もうやめろ！","ENG":"Dammit! Stop shooting me!","TWN":"該死的！別再開啦！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"거기 당신! 당신이 이 쇳덩이를 수리해 달라고 의뢰한 거 아닌가?","JPN":"そこのお前さん！　お前さんがこの鉄の塊の修理を依頼したんだろ？","ENG":"Hey, you! Aren't you the one who requested this hunk of metal be repaired?","TWN":"就是你！是你委託我修理這塊廢鐵的不是嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};